ship legacy","Begin your leadership legacy journey"],"methodology":"Lecture; Discussion","origin":"Gotham (gC + GGS)","src":["4344becb-a524-4501-aa32-4394a35059be","bd25a5fe-cbbd-4f6b-b890-40059137f757"]}]$cat$::jsonb)
    AS x(id uuid, title text, status text, difficulty text, duration int,
         tags jsonb, domain text, objectives jsonb, methodology text, origin text, src jsonb)
)
UPDATE courses c SET
  title = COALESCE(NULLIF(d.title, ''), c.title),
  status = COALESCE(NULLIF(d.status, ''), c.status),
  difficulty_level = COALESCE(NULLIF(d.difficulty, ''), c.difficulty_level),
  estimated_duration = COALESCE(d.duration, c.estimated_duration),
  tags = CASE WHEN jsonb_array_length(COALESCE(d.tags, '[]'::jsonb)) > 0
              THEN ARRAY(SELECT jsonb_array_elements_text(d.tags)) ELSE c.tags END,
  category_id = CASE WHEN COALESCE(d.domain, '') <> ''
                     THEN COALESCE((SELECT id FROM categories WHERE name = d.domain), c.category_id)
                     ELSE c.category_id END,
  metadata = COALESCE(c.metadata, '{}'::jsonb)
    || CASE WHEN jsonb_array_length(COALESCE(d.objectives, '[]'::jsonb)) > 0
            THEN jsonb_build_object('learning_outcomes', d.objectives) ELSE '{}'::jsonb END
    || CASE WHEN COALESCE(d.methodology, '') <> ''
            THEN jsonb_build_object('methodology', d.methodology) ELSE '{}'::jsonb END
    || CASE WHEN jsonb_array_length(COALESCE(d.tags, '[]'::jsonb)) > 0
            THEN jsonb_build_object('skills', d.tags) ELSE '{}'::jsonb END
    || jsonb_build_object('catalog_audit', jsonb_strip_nulls(jsonb_build_object(
         'origin', d.origin,
         'imported_at', $cat$2026-07-02$cat$,
         'sheet', $cat$Course_Catalog_Audit_MERGED_MASTER.xlsx$cat$,
         'source_course_ids', d.src))),
  updated_at = now()
FROM d WHERE c.id = d.id;
